styles:
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --sidebar-bg: #DAE4F8;
      --main-bg: #FFFCF8;
      --blue: #448AFF;
      --blue-dark: #3a7aee;
      --text: #1a1a1a;
      --muted: #6b6b6b;
      --brown: #b8956f;
      --brown-border: #d4b896;
      --card-hover: #FFEED5;
      --star-filled: #f5a623;
      --sidebar-width: 248px;
      --font: 'Montserrat', sans-serif;
    }

    html, body { height: 100%; }

    body {
      font-family: var(--font);
      background: var(--main-bg);
      color: var(--text);
      -webkit-font-smoothing: antialiased;
    }

    .app { display: flex; min-height: 100vh; }

    .sidebar {
      width: var(--sidebar-width);
      flex-shrink: 0;
      background: var(--sidebar-bg);
      display: flex;
      flex-direction: column;
      padding: 28px 20px 32px;
      min-height: 100vh;
      position: relative;
      transition: width 0.22s ease, padding 0.22s ease;
    }

    .sidebar__collapse {
      position: absolute;
      top: 14px;
      right: 12px;
      width: 34px;
      height: 34px;
      border: none;
      border-radius: 8px;
      background: transparent;
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .sidebar__collapse:hover { background: rgba(68, 138, 255, 0.12); }
    .sidebar__collapse svg { width: 22px; height: 22px; display: block; }
    .app.is-sidebar-collapsed .sidebar__collapse { display: none; }

    .sidebar__toggle {
      width: 54px;
      height: 54px;
      margin: 0 auto 18px;
      border: none;
      border-radius: 16px;
      background: rgba(68, 138, 255, 0.12);
      display: none;
      align-items: center;
      justify-content: center;
      cursor: pointer;
    }

    .app.is-sidebar-collapsed .sidebar__toggle { display: flex; }

    .sidebar__toggle img {
      width: 32px;
      height: 32px;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
    }

    .sidebar__brand {
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
      margin-bottom: 36px;
    }

    .sidebar__logo {
      width: 120px;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
      margin-bottom: 4px;
    }

    .sidebar__title {
      font-size: 15px;
      font-weight: 800;
      color: var(--blue);
      letter-spacing: 0.06em;
    }

    .nav { list-style: none; display: flex; flex-direction: column; gap: 6px; }

    .nav a {
      display: flex;
      align-items: center;
      gap: 12px;
      padding: 12px 16px;
      border-radius: 12px;
      color: var(--blue);
      font-size: 14px;
      font-weight: 600;
      text-decoration: none;
      transition: background 0.15s ease;
    }

    .nav a svg { width: 20px; height: 20px; flex-shrink: 0; stroke: currentColor; fill: none; }
    .nav a:hover:not(.is-active) { background: rgba(68, 138, 255, 0.12); }
    .nav a.is-active { background: var(--blue); color: #fff; }
    .nav a.is-active svg { stroke: #fff; }
    .nav a .nav-icon--saved { stroke: none; }
    .nav a .nav-icon--saved path { fill: currentColor; }
    .nav a .nav-icon--attendance { stroke: none; }
    .nav a .nav-icon--attendance path { fill: currentColor; }
    .nav a .nav-icon--events { stroke: none; }
    .nav a .nav-icon--events path { fill: currentColor; }
    .nav a .nav-icon--home { stroke: none; }
    .nav a .nav-icon--home path { fill: currentColor; }
    .nav a .nav-icon--certificates { stroke: none; }
    .nav a .nav-icon--certificates path { fill: currentColor; }
    .nav a.is-active [class*="nav-icon--"] > g { filter: none; }

    .sidebar__spacer { flex: 1; min-height: 24px; }
    .nav--bottom { margin-top: auto; padding-top: 16px; }

    .app.is-sidebar-collapsed .sidebar { width: 102px; padding: 28px 12px 24px; }
    .app.is-sidebar-collapsed .sidebar__brand { display: none; }
    .app.is-sidebar-collapsed .nav a { justify-content: center; gap: 0; padding: 14px 0; font-size: 0; }
    .app.is-sidebar-collapsed .nav a svg { width: 24px; height: 24px; }
    .app.is-sidebar-collapsed .nav a.is-active { width: 56px; margin: 0 auto; }

    .main {
      flex: 1;
      min-width: 0;
      overflow-y: auto;
      padding: 32px 40px 48px;
    }

    .main__top {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 16px;
      margin-bottom: 28px;
    }

    .main__greeting {
      font-size: clamp(1.75rem, 3vw, 2.25rem);
      font-weight: 700;
      color: var(--blue);
      line-height: 1.15;
    }

    .main__tools {
      display: flex;
      align-items: center;
      gap: 14px;
    }

    .main__user-name {
      font-size: 14px;
      font-weight: 600;
      color: var(--blue);
      white-space: nowrap;
    }

    .tool-btn {
      width: 40px;
      height: 40px;
      border: none;
      border-radius: 50%;
      background: transparent;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      color: var(--blue);
      flex-shrink: 0;
    }

    .tool-btn:hover { background: rgba(68, 138, 255, 0.1); }
    .tool-btn--avatar { background: #c5d9fc; }
    .tool-btn--help { background: #c5d9fc; color: #fff; }
    .tool-btn--help:hover { background: #b5cffc; color: #fff; }
    .tool-btn--help svg { width: 22px; height: 22px; flex-shrink: 0; }
    .tool-btn svg { width: 22px; height: 22px; }

    /* ── Detail sub-header ── */
    .detail-head {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 16px;
      margin-bottom: 32px;
      flex-wrap: wrap;
    }

    .detail-back {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      color: var(--text);
      font-size: 16px;
      font-weight: 700;
      text-decoration: none;
      transition: color 0.15s ease;
    }

    .detail-back:hover { color: var(--blue); }

    .detail-back svg {
      width: 20px;
      height: 20px;
      flex-shrink: 0;
    }

    .detail-submitted {
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 0.06em;
      color: var(--brown);
      text-align: right;
      line-height: 1.4;
    }

    /* ── Detail fields ── */
    .detail-panel {
      max-width: 900px;
    }

    .detail-row {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 24px;
      padding: 18px 0;
      border-bottom: 1px solid rgba(184, 149, 111, 0.2);
    }

    .detail-row__label {
      font-size: 14px;
      font-weight: 600;
      color: var(--text);
      flex-shrink: 0;
      min-width: 140px;
    }

    .detail-row__value {
      font-size: 14px;
      font-weight: 600;
      color: var(--text);
      text-align: right;
      flex: 1;
    }

    .detail-block {
      padding: 22px 0;
      border-bottom: 1px solid rgba(184, 149, 111, 0.2);
    }

    .detail-block:last-child {
      border-bottom: none;
      padding-bottom: 0;
    }

    .detail-block__label {
      font-size: 14px;
      font-weight: 600;
      color: var(--text);
      margin-bottom: 14px;
      display: block;
    }

    .detail-stars {
      display: flex;
      align-items: center;
      justify-content: flex-end;
      gap: 4px;
    }

    .detail-stars__star {
      width: 22px;
      height: 22px;
      color: #d0d0d0;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .detail-stars__star svg {
      width: 22px;
      height: 22px;
      fill: none;
      stroke: currentColor;
      stroke-width: 1.5;
    }

    .detail-stars__star.is-filled {
      color: var(--star-filled);
    }

    .detail-stars__star.is-filled svg {
      fill: currentColor;
      stroke: currentColor;
    }

    .detail-media {
      display: flex;
      gap: 16px;
      flex-wrap: wrap;
    }

    .detail-media__thumb {
      width: 200px;
      height: 130px;
      border-radius: 8px;
      background:
        linear-gradient(135deg, #3a4a5c 0%, #1e2a38 100%);
      border: 1px solid rgba(184, 149, 111, 0.35);
      flex-shrink: 0;
      position: relative;
      overflow: hidden;
    }

    .detail-media__thumb::before {
      content: '';
      position: absolute;
      bottom: 0;
      left: 50%;
      transform: translateX(-50%);
      width: 60px;
      height: 70px;
      border-radius: 30px 30px 0 0;
      background: linear-gradient(180deg, #6b7b8d 0%, #4a5568 100%);
    }

    .detail-media__thumb::after {
      content: '';
      position: absolute;
      top: 20px;
      left: 0;
      right: 0;
      height: 40px;
      background: linear-gradient(180deg, rgba(255, 200, 80, 0.35) 0%, transparent 100%);
    }

    .detail-media__thumb--alt {
      background: linear-gradient(135deg, #2d3e50 0%, #1a2530 100%);
    }

    .detail-media__thumb--alt::before {
      width: 50px;
      height: 60px;
      background: linear-gradient(180deg, #5a6a7a 0%, #3d4a58 100%);
    }

    .detail-comment {
      width: 100%;
      min-height: 160px;
      padding: 16px 18px;
      border: 1px solid var(--brown-border);
      border-radius: 10px;
      background: #fff;
      font-family: var(--font);
      font-size: 14px;
      font-weight: 500;
      color: var(--text);
      line-height: 1.55;
      resize: vertical;
      outline: none;
      transition: border-color 0.15s ease, box-shadow 0.15s ease;
    }

    .detail-comment:focus {
      border-color: var(--blue);
      box-shadow: 0 0 0 3px rgba(68, 138, 255, 0.12);
    }

    .detail-comment::placeholder {
      color: #b0b0b0;
    }

    @media (max-width: 900px) {
      .app { flex-direction: column; }
      .sidebar { width: 100%; min-height: auto; padding: 20px; }
      .sidebar__collapse, .sidebar__toggle { display: none !important; }
      .sidebar__spacer, .nav--bottom { display: none; }
      .main { padding: 24px 20px 40px; }
      .main__user-name { display: none; }
      .detail-row { flex-direction: column; align-items: flex-start; gap: 8px; }
      .detail-row__value, .detail-stars { text-align: left; justify-content: flex-start; }
      .detail-head { flex-direction: column; align-items: flex-start; }
      .detail-submitted { text-align: left; }
      .detail-media__thumb { width: 100%; max-width: 280px; }
    }

scripts.value:
(function () {
      var app = document.querySelector('.app');
      var toggle = document.getElementById('sidebar-toggle');
      var collapse = document.getElementById('sidebar-collapse');
      var storageKey = 'dc_sidebar_collapsed';

      function setSidebarCollapsed(collapsed) {
        app.classList.toggle('is-sidebar-collapsed', collapsed);
        localStorage.setItem(storageKey, collapsed);
      }

      if (localStorage.getItem(storageKey) === 'true' && window.innerWidth > 900) {
        setSidebarCollapsed(true);
      }

      collapse.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(true);
      });

      toggle.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(false);
      });
    })();
